/* lgsMgmtMapper.updateLgsPrdtSrlMst */
UPDATE LGS_PRDT_SRL_MST A
SET 
		CHNG_DTTM = SYSDATE
	, OLD_YN	          = #{oldYn,jdbcType=VARCHAR}             
	, ORGN_ID	          = #{orgnId,jdbcType=VARCHAR}            
	, IMEI	        	  = #{imei,jdbcType=VARCHAR}              
	, PRDT_SRL_NUM_FMT	  = #{prdtSrlNumFmt,jdbcType=VARCHAR}     
	, PRDT_PRPOS_CD	      = #{prdtPrposCd,jdbcType=VARCHAR}       
	, LAST_INOUT_ID	      = #{lastInoutId,jdbcType=VARCHAR}       
	, PRDT_STAT_CD	      = #{prdtStatCd,jdbcType=VARCHAR}        
	, SUPLY_CPNY_ORD_NUM = #{suplyCpnyOrdNum,jdbcType=VARCHAR}   
	, LAST_CHNG_HST_NUM	  = #{lastChngHstNum,jdbcType=VARCHAR}    
	, LOGIS_PROC_STAT_CD = #{logisProcStatCd,jdbcType=VARCHAR}   
	, MYCPNY_REQ_YN	      = #{mycpnyReqYn,jdbcType=VARCHAR}       
	, PRDT_COLR_CD	      = #{prdtColrCd,jdbcType=VARCHAR}        
	, SVC_PROC_STAT_CD	  = #{svcProcStatCd,jdbcType=VARCHAR}     
	, INPUT_DT	          = #{inputDt,jdbcType=VARCHAR}           
	, PRDT_TYPE_CD	      = #{prdtTypeCd,jdbcType=VARCHAR}        
	, CRE_DT	         = #{creDt,jdbcType=VARCHAR}             
	, WIFI_MAC_ID	      = #{wifiMacId,jdbcType=VARCHAR}         
	, SVC_CT_NUM	      = TRIM(#{svcCtNum,jdbcType=VARCHAR})          
	, SVC_OPEN_DT	      = #{svcOpenDt,jdbcType=VARCHAR}         
	, SVC_OPEN_TM	      = #{svcOpenTm,jdbcType=VARCHAR}         
	, ESN	        	  = #{esn,jdbcType=VARCHAR}               
	, CERT_KEY	          = #{certKey,jdbcType=VARCHAR}           
	, TCN_STD_CNFM_CERTNO = #{tcnStdCnfmCertno,jdbcType=VARCHAR}  
	, WIBRO_IMEI	      = #{wibroImei,jdbcType=VARCHAR}         
	, FIXED_ID	          = #{fixedId,jdbcType=VARCHAR}           
	, RFNO	        	  = #{rfno,jdbcType=VARCHAR}              
	, NAMING	         = #{naming,jdbcType=VARCHAR}            
	, NSN	        	  = #{nsn,jdbcType=VARCHAR}               
	, WIBRO_MAC_ID	      = #{wibroMacId,jdbcType=VARCHAR}        
	, INVTR_DAY_CNT	      = #{invtrDayCnt,jdbcType=VARCHAR}     
	, IN_UNIT_PRICE	      =  #{inUnitPrice,jdbcType=VARCHAR}    
	, IN_DT	        	  = #{inDt,jdbcType=VARCHAR}              
	, OUT_DT	         = #{outDt,jdbcType=VARCHAR}             
	, IN_UNIT_PRICE	  =  #{inUnitPrice,jdbcType=VARCHAR}        
	, OUT_UNIT_PRICE	  =  #{outUnitPrice,jdbcType=VARCHAR}        
	, IF_QUE_NUM	  =  #{ifQueNum,jdbcType=VARCHAR}               
	, SLS_DT  =  #{slsDt,jdbcType=VARCHAR}               
	, CAN_DT  =  #{canDt,jdbcType=VARCHAR}               
	, CHNG_ID	         = #{userId,jdbcType=VARCHAR}           
WHERE A.PRDT_ID  = #{prdtId,jdbcType=VARCHAR} 
  AND A.PRDT_SRL_NUM  = #{prdtSrlNum,jdbcType=VARCHAR}

/* lgsMgmtMapper.updateInvtrDayMst */
UPDATE	LGS_INVTR_DAY_MST
SET		CHNG_DTTM = SYSDATE
		, GOOD_STRG_INVTR_QNTY = NVL(GOOD_STRG_INVTR_QNTY,0) + #{goodStrgInvtrQnty, jdbcType=NUMERIC}
		, NG_STRG_INVTR_QNTY = NVL(NG_STRG_INVTR_QNTY,0) + #{ngStrgInvtrQnty, jdbcType=NUMERIC}
		, IN_DUE_QNTY = NVL(IN_DUE_QNTY,0) + #{inDueQnty, jdbcType=NUMERIC}
		, OUT_RSV_QNTY = NVL(OUT_RSV_QNTY,0) + #{outRsvQnty, jdbcType=NUMERIC}
, CHNG_ID = #{userId, jdbcType=VARCHAR} 
WHERE	STD_DT  = TO_CHAR(SYSDATE,'YYYYMMDD')
		AND ORGN_ID = #{orgnId, jdbcType=VARCHAR}
		AND PRDT_ID = #{prdtId, jdbcType=VARCHAR}
		AND OLD_YN  = #{oldYn, jdbcType=VARCHAR}

MERGE  /* lgsMgmtMapper.mgrOtcpInvMst */
 INTO  LGS_OTCP_INVTR
USING  DUAL
   ON  (	ORGN_ID = #{orgnId, jdbcType=VARCHAR}
		AND PRDT_ID = #{prdtId, jdbcType=VARCHAR}
		AND OLD_YN  = #{oldYn, jdbcType=VARCHAR}
	   )

 WHEN  MATCHED THEN

	   UPDATE
		  SET  CHNG_ID = #{userId, jdbcType=VARCHAR}
			 , CHNG_DTTM = SYSDATE
			 , GOOD_STRG_INVTR_QNTY = GOOD_STRG_INVTR_QNTY + #{goodStrgInvtrQnty, jdbcType=NUMERIC}
			 , NG_STRG_INVTR_QNTY = NG_STRG_INVTR_QNTY + #{ngStrgInvtrQnty, jdbcType=NUMERIC}
			 , IN_DUE_QNTY = NVL(IN_DUE_QNTY,0) + #{inDueQnty, jdbcType=NUMERIC}
			 , OUT_RSV_QNTY = NVL(OUT_RSV_QNTY,0) + #{outRsvQnty, jdbcType=NUMERIC}
			 , SALE_QTY = SALE_QTY + #{saleQty, jdbcType=NUMERIC}
			 , CAN_QTY = CAN_QTY + #{canQty, jdbcType=NUMERIC}

 WHEN  NOT MATCHED THEN

	  INSERT  (
			  ORGN_ID                                        --조직ID
			, PRDT_ID                                        --제품ID
			, OLD_YN                                         --중고여부
			, GOOD_STRG_INVTR_QNTY                           --재고수량
			, NG_STRG_INVTR_QNTY                             --불량수량
			, IN_DUE_QNTY                                    --입고예정수량
			, OUT_RSV_QNTY                                   --출고예정수량
			, SALE_QTY                                       --판매수량
			, CAN_QTY                                        --해지수량
			, REGST_ID                                       --등록자ID
			, REG_DTTM                                       --등록일시
			, CHNG_ID                                        --변경자ID
			, CHNG_DTTM                                      --변경일시
	) VALUES (
			  #{orgnId, jdbcType=VARCHAR}
			, #{prdtId, jdbcType=VARCHAR}
			, #{oldYn, jdbcType=VARCHAR}
			, #{goodStrgInvtrQnty, jdbcType=NUMERIC}
			, #{ngStrgInvtrQnty, jdbcType=NUMERIC}
			, #{inDueQnty, jdbcType=NUMERIC}
			, #{outRsvQnty, jdbcType=NUMERIC}
			, #{saleQty, jdbcType=NUMERIC}
			, #{canQty, jdbcType=NUMERIC}
			, #{userId, jdbcType=VARCHAR}
			, SYSDATE
			, #{userId, jdbcType=VARCHAR}
			, SYSDATE
	)
